/* ═══════════════════════════════════════════════════════════════════════════
   AURA ALPHA — Strategy Compare Page
   Side-by-side comparison of 2-3 strategies: metrics table, equity curves,
   drawdown overlay, region performance, signal frequency, risk-adjusted
   scatter plot, and AI-generated verdict.
   Route: /strategies/compare?ids=breakout,the_5_day_bounce
   ═══════════════════════════════════════════════════════════════════════════ */
import { useState, useEffect, useMemo } from 'react';
import { useSearchParams, useNavigate } from 'react-router-dom';
import { tokens } from '../styles/tokens';
import GlassPanel from '../components/ui/GlassPanel';
import usePageTitle from '../hooks/usePageTitle';
import { api } from '../utils/api';
import s from './StrategyComparePage.module.css';

// ── Design tokens ──────────────────────────────────────────────────────────
const T = {
  bg: tokens.color.bg, surface: tokens.color.surface, border: tokens.color.border,
  text: tokens.color.text, textSec: tokens.color.textSecondary,
  green: tokens.color.green, red: tokens.color.red, blue: tokens.color.blue,
  amber: tokens.color.amber, purple: tokens.color.purple, cyan: tokens.color.cyan,
  mono: tokens.font.mono, sans: tokens.font.sans,
};

// Strategy colors for charts (up to 3)
const STRAT_COLORS = ['#60A5FA', '#22C55E', '#F59E0B'];

// ── Helpers ────────────────────────────────────────────────────────────────
const fmtNum = (v, d = 2) => (v == null || isNaN(v)) ? '--' : Number(v).toFixed(d);
const fmtPct = (v) => (v == null || isNaN(v)) ? '--' : `${Number(v).toFixed(1)}%`;

function metricColor(value, thresholds) {
  if (value == null) return T.textSec;
  for (const [thresh, color] of thresholds) {
    if (value >= thresh) return color;
  }
  return T.textSec;
}

// ── SVG Equity Curve Overlay ───────────────────────────────────────────────
function EquityCurveChart({ strategies }) {
  const W = 800, H = 200, PAD = 40;

  // Normalize all curves to same x-axis (index-based since dates may differ)
  const curves = strategies.map((strat, si) => {
    const ec = strat.equity_curve || [];
    if (ec.length === 0) return [];
    return ec.map((pt, i) => ({
      x: ec.length > 1 ? PAD + (i / (ec.length - 1)) * (W - 2 * PAD) : W / 2,
      y: pt.pnl ?? 0,
      date: pt.date,
    }));
  });

  // Find global Y range
  const allY = curves.flat().map(p => p.y);
  if (allY.length === 0) return <div className={s.loadingBox}>No equity data</div>;
  const minY = Math.min(...allY, 0);
  const maxY = Math.max(...allY, 0.01);
  const range = maxY - minY || 1;

  const mapY = (y) => PAD + (1 - (y - minY) / range) * (H - 2 * PAD);

  // Zero line
  const zeroY = mapY(0);

  return (
    <svg width="100%" viewBox={`0 0 ${W} ${H}`} className={s.chartSvg}>
      {/* Grid */}
      <line x1={PAD} y1={PAD} x2={PAD} y2={H - PAD} stroke="rgba(255,255,255,0.06)" />
      <line x1={PAD} y1={H - PAD} x2={W - PAD} y2={H - PAD} stroke="rgba(255,255,255,0.06)" />
      {/* Zero line */}
      {minY < 0 && (
        <line x1={PAD} y1={zeroY} x2={W - PAD} y2={zeroY}
          stroke="rgba(255,255,255,0.1)" strokeDasharray="4" />
      )}
      {/* Y-axis labels */}
      <text x={PAD - 6} y={PAD + 4} textAnchor="end" fill={T.textSec} fontSize="9" fontFamily={T.mono}>
        ${fmtNum(maxY, 0)}
      </text>
      <text x={PAD - 6} y={H - PAD + 4} textAnchor="end" fill={T.textSec} fontSize="9" fontFamily={T.mono}>
        ${fmtNum(minY, 0)}
      </text>
      {/* Curves */}
      {curves.map((pts, si) => {
        if (pts.length < 2) return null;
        const polyline = pts.map(p => `${p.x},${mapY(p.y)}`).join(' ');
        const lastPt = pts[pts.length - 1];
        return (
          <g key={si}>
            <polyline points={polyline} fill="none" stroke={STRAT_COLORS[si]}
              strokeWidth="2" strokeLinejoin="round" opacity="0.9" />
            <circle cx={lastPt.x} cy={mapY(lastPt.y)} r="3" fill={STRAT_COLORS[si]} />
            <text x={lastPt.x + 6} y={mapY(lastPt.y) + 4} fill={STRAT_COLORS[si]}
              fontSize="10" fontWeight="700" fontFamily={T.mono}>
              ${fmtNum(lastPt.y, 0)}
            </text>
          </g>
        );
      })}
    </svg>
  );
}

// ── SVG Drawdown Overlay ───────────────────────────────────────────────────
function DrawdownChart({ strategies }) {
  const W = 800, H = 140, PAD = 40;

  const curves = strategies.map((strat) => {
    const dc = strat.drawdown_curve || [];
    return dc.map((pt, i) => ({
      x: dc.length > 1 ? PAD + (i / (dc.length - 1)) * (W - 2 * PAD) : W / 2,
      y: pt.drawdown ?? 0,
    }));
  });

  const allY = curves.flat().map(p => p.y);
  if (allY.length === 0) return <div className={s.loadingBox}>No drawdown data</div>;
  const minY = Math.min(...allY, -0.01);
  const maxY = 0;
  const range = maxY - minY || 0.01;

  const mapY = (y) => PAD + (1 - (y - minY) / range) * (H - 2 * PAD);

  return (
    <svg width="100%" viewBox={`0 0 ${W} ${H}`} className={s.chartSvg}>
      {/* Zero line */}
      <line x1={PAD} y1={mapY(0)} x2={W - PAD} y2={mapY(0)}
        stroke="rgba(255,255,255,0.1)" strokeDasharray="4" />
      {/* Y-axis labels */}
      <text x={PAD - 6} y={mapY(0) + 4} textAnchor="end" fill={T.textSec} fontSize="9" fontFamily={T.mono}>
        0%
      </text>
      <text x={PAD - 6} y={mapY(minY) + 4} textAnchor="end" fill={T.textSec} fontSize="9" fontFamily={T.mono}>
        {fmtPct(minY * 100)}
      </text>
      {/* Drawdown fills */}
      {curves.map((pts, si) => {
        if (pts.length < 2) return null;
        const zeroLine = mapY(0);
        const fillPts = `${pts[0].x},${zeroLine} ` +
          pts.map(p => `${p.x},${mapY(p.y)}`).join(' ') +
          ` ${pts[pts.length - 1].x},${zeroLine}`;
        const polyline = pts.map(p => `${p.x},${mapY(p.y)}`).join(' ');
        return (
          <g key={si}>
            <polygon points={fillPts} fill={STRAT_COLORS[si]} opacity="0.08" />
            <polyline points={polyline} fill="none" stroke={STRAT_COLORS[si]}
              strokeWidth="1.5" strokeLinejoin="round" opacity="0.7" />
          </g>
        );
      })}
    </svg>
  );
}

// ── Risk-Adjusted Scatter Plot ─────────────────────────────────────────────
function RiskScatterPlot({ strategies }) {
  const W = 400, H = 300, PAD = 50;

  const points = strategies.map((strat, si) => {
    const m = strat.metrics || {};
    return {
      x: Math.abs(m.max_drawdown || 0) * 100,  // drawdown % (risk)
      y: (m.avg_return || 0) * 100,              // return % (reward)
      label: strat.label,
      color: STRAT_COLORS[si],
    };
  });

  const xs = points.map(p => p.x);
  const ys = points.map(p => p.y);
  const minX = 0, maxX = Math.max(...xs, 1) * 1.2;
  const minY = Math.min(...ys, 0) * 1.2, maxY = Math.max(...ys, 1) * 1.2;

  const mapX = (v) => PAD + (v / (maxX || 1)) * (W - 2 * PAD);
  const mapYv = (v) => PAD + (1 - (v - minY) / ((maxY - minY) || 1)) * (H - 2 * PAD);

  return (
    <svg width="100%" viewBox={`0 0 ${W} ${H}`} className={s.chartSvg}>
      {/* Axes */}
      <line x1={PAD} y1={PAD} x2={PAD} y2={H - PAD} stroke="rgba(255,255,255,0.06)" />
      <line x1={PAD} y1={H - PAD} x2={W - PAD} y2={H - PAD} stroke="rgba(255,255,255,0.06)" />
      {/* Axis labels */}
      <text x={W / 2} y={H - 8} textAnchor="middle" fill={T.textSec} fontSize="10" fontFamily={T.sans}>
        Max Drawdown %
      </text>
      <text x={12} y={H / 2} textAnchor="middle" fill={T.textSec} fontSize="10" fontFamily={T.sans}
        transform={`rotate(-90, 12, ${H / 2})`}>
        Avg Return %
      </text>
      {/* Points */}
      {points.map((pt, i) => (
        <g key={i}>
          <circle cx={mapX(pt.x)} cy={mapYv(pt.y)} r="8" fill={pt.color} opacity="0.8" />
          <circle cx={mapX(pt.x)} cy={mapYv(pt.y)} r="8" fill="none" stroke={pt.color} strokeWidth="2" />
          <text x={mapX(pt.x)} y={mapYv(pt.y) - 14} textAnchor="middle" fill={pt.color}
            fontSize="10" fontWeight="700" fontFamily={T.sans}>
            {pt.label}
          </text>
          <text x={mapX(pt.x)} y={mapYv(pt.y) + 20} textAnchor="middle" fill={T.textSec}
            fontSize="9" fontFamily={T.mono}>
            DD:{fmtNum(pt.x, 1)}% / R:{fmtNum(pt.y, 2)}%
          </text>
        </g>
      ))}
    </svg>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
// MAIN COMPONENT
// ═══════════════════════════════════════════════════════════════════════════
export default function StrategyComparePage() {
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  const ids = searchParams.get('ids') || '';
  const names = ids.split(',').filter(Boolean);

  usePageTitle('Compare Strategies');

  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    if (names.length < 2) {
      setError('Select at least 2 strategies to compare');
      setLoading(false);
      return;
    }
    setLoading(true);
    setError(null);
    api(`/strategies/compare?names=${encodeURIComponent(ids)}`)
      .then(res => {
        if (res && res.strategies) {
          setData(res);
        } else {
          setError('Failed to load comparison data');
        }
        setLoading(false);
      })
      .catch(() => {
        setError('Failed to load comparison data');
        setLoading(false);
      });
  }, [ids]); // eslint-disable-line react-hooks/exhaustive-deps

  const strategies = data?.strategies || [];
  const verdict = data?.verdict || {};

  // ── Metrics rows config ──────────────────────────────────────────────
  const metricRows = useMemo(() => [
    {
      label: 'Sharpe Ratio',
      key: 'sharpe',
      fmt: v => fmtNum(v, 2),
      thresholds: [[1.5, T.green], [0.5, T.amber], [-Infinity, T.red]],
      higherBetter: true,
    },
    {
      label: 'Win Rate',
      key: 'win_rate',
      fmt: v => fmtPct(v),
      thresholds: [[60, T.green], [50, T.text], [0, T.red]],
      higherBetter: true,
    },
    {
      label: 'Profit Factor',
      key: 'profit_factor',
      fallback: 'profit_factor_raw',
      fmt: v => v >= 50 ? '\u221E' : fmtNum(v, 2),
      thresholds: [[2.0, T.green], [1.3, T.amber], [0, T.red]],
      higherBetter: true,
    },
    {
      label: 'Max Drawdown',
      key: 'max_drawdown',
      fmt: v => v ? `-${fmtPct(Math.abs(v) * 100)}` : '--',
      thresholds: [[-0.05, T.green], [-0.15, T.amber], [-Infinity, T.red]],
      higherBetter: false, // lower (closer to 0) is better, but values are negative
      compareInvert: true,
    },
    {
      label: 'Total Trades',
      key: 'total_trades',
      fmt: v => v != null ? v.toLocaleString() : '--',
      thresholds: [[50, T.green], [20, T.amber], [0, T.red]],
      higherBetter: true,
    },
    {
      label: 'Avg Return/Trade',
      key: 'avg_return',
      fmt: v => fmtPct((v || 0) * 100),
      thresholds: [[0.03, T.green], [0, T.text], [-Infinity, T.red]],
      higherBetter: true,
    },
    {
      label: 'Total P&L',
      key: 'total_pnl',
      fmt: v => v != null ? `$${fmtNum(v, 2)}` : '--',
      thresholds: [[0, T.green], [-Infinity, T.red]],
      higherBetter: true,
    },
    {
      label: 'Signals/Month',
      key: 'signal_frequency',
      fmt: v => v != null ? fmtNum(v, 1) : '--',
      thresholds: [[5, T.blue], [1, T.amber], [0, T.textSec]],
      higherBetter: true,
    },
  ], []);

  // ── Find best value per metric ───────────────────────────────────────
  const getBest = (row) => {
    const values = strategies.map(strat => {
      const m = strat.metrics || {};
      return m[row.key] ?? (row.fallback ? m[row.fallback] : null);
    });
    if (values.every(v => v == null)) return -1;
    if (row.compareInvert) {
      // For drawdown: closest to 0 is best (least negative)
      let bestIdx = -1;
      let bestVal = -Infinity;
      values.forEach((v, i) => {
        if (v != null && v > bestVal) { bestVal = v; bestIdx = i; }
      });
      return bestIdx;
    }
    if (row.higherBetter) {
      let bestIdx = -1;
      let bestVal = -Infinity;
      values.forEach((v, i) => {
        if (v != null && v > bestVal) { bestVal = v; bestIdx = i; }
      });
      return bestIdx;
    }
    let bestIdx = -1;
    let bestVal = Infinity;
    values.forEach((v, i) => {
      if (v != null && v < bestVal) { bestVal = v; bestIdx = i; }
    });
    return bestIdx;
  };

  // ── Collect all regions across strategies ─────────────────────────────
  const allRegions = useMemo(() => {
    const regionSet = new Set();
    strategies.forEach(strat => {
      Object.keys(strat.region_performance || {}).forEach(r => regionSet.add(r));
    });
    return [...regionSet].sort();
  }, [strategies]);

  // ── Loading ─────────────────────────────────────────────────────────
  if (loading) {
    return (
      <div className={s.page}>
        <div className={s.header}>
          <h1 className={s.title}>Strategy Comparison</h1>
        </div>
        <div className={s.loadingBox}>
          <svg width="20" height="20" viewBox="0 0 24 24" fill="none"
            stroke="currentColor" strokeWidth="2" className={s.spinner}>
            <path d="M21 12a9 9 0 11-6.219-8.56" />
          </svg>
          Loading comparison...
        </div>
      </div>
    );
  }

  // ── Error ───────────────────────────────────────────────────────────
  if (error || strategies.length < 2) {
    return (
      <div className={s.page}>
        <div className={s.header}>
          <h1 className={s.title}>Strategy Comparison</h1>
        </div>
        <div className={s.errorCard}>
          <div className={s.errorTitle}>
            {error || 'Not enough strategies selected'}
          </div>
          <div className={s.errorDesc}>
            Select 2 or 3 strategies from the catalogue to compare side by side.
          </div>
          <button onClick={() => navigate('/strategies')} className={s.backBtn}
            style={{ margin: '0 auto', display: 'block' }}>
            Browse Strategies
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className={s.page}>
      {/* ═══ Header ══════════════════════════════════════════════════════ */}
      <div className={s.header}>
        <h1 className={s.title}>Strategy Comparison</h1>
        <button onClick={() => navigate('/strategies')} className={s.backBtn}>
          Back to Catalogue
        </button>
      </div>

      {/* ═══ Strategy pills ══════════════════════════════════════════════ */}
      <div className={s.strategyPills}>
        {strategies.map((strat, i) => (
          <div key={strat.key} className={s.pill}
            style={{
              borderColor: STRAT_COLORS[i],
              background: `${STRAT_COLORS[i]}0A`,
              color: STRAT_COLORS[i],
            }}
            onClick={() => navigate(`/strategies/${encodeURIComponent(strat.key)}`)}
          >
            <span className={s.pillDot} style={{ background: STRAT_COLORS[i] }} />
            {strat.label}
            <span className={s.pillDir} style={{
              background: strat.direction === 'long' ? 'rgba(34,197,94,0.15)' :
                strat.direction === 'short' ? 'rgba(239,68,68,0.15)' : 'rgba(96,165,250,0.15)',
              color: strat.direction === 'long' ? T.green :
                strat.direction === 'short' ? T.red : T.blue,
            }}>
              {strat.direction || '--'}
            </span>
          </div>
        ))}
      </div>

      {/* ═══ 1. Metrics Table ════════════════════════════════════════════ */}
      <GlassPanel className={s.metricsPanel}>
        <div className={s.sectionTitle}>
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke={T.blue}
            strokeWidth="2" className={s.sectionIcon}>
            <rect x="3" y="3" width="7" height="7" />
            <rect x="14" y="3" width="7" height="7" />
            <rect x="14" y="14" width="7" height="7" />
            <rect x="3" y="14" width="7" height="7" />
          </svg>
          Key Metrics
        </div>
        <div style={{ overflowX: 'auto' }}>
          <table className={s.metricsTable}>
            <thead>
              <tr>
                <th>Metric</th>
                {strategies.map((strat, i) => (
                  <th key={strat.key} style={{ color: STRAT_COLORS[i] }}>
                    {strat.label}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {metricRows.map(row => {
                const bestIdx = getBest(row);
                return (
                  <tr key={row.key}>
                    <td className={s.metricLabel}>{row.label}</td>
                    {strategies.map((strat, i) => {
                      const m = strat.metrics || {};
                      const val = m[row.key] ?? (row.fallback ? m[row.fallback] : null);
                      const color = metricColor(
                        row.key === 'max_drawdown' ? val : val,
                        row.thresholds
                      );
                      const isBest = i === bestIdx;
                      return (
                        <td key={strat.key}
                          className={isBest ? s.bestCell : undefined}
                          style={{
                            color,
                            background: isBest ? `${T.green}08` : 'transparent',
                          }}>
                          {val != null ? row.fmt(val) : '--'}
                        </td>
                      );
                    })}
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </GlassPanel>

      {/* ═══ 2. Equity Curve Overlay ═════════════════════════════════════ */}
      <GlassPanel className={s.chartPanel}>
        <div className={s.sectionTitle}>
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke={T.green}
            strokeWidth="2" className={s.sectionIcon}>
            <polyline points="22 7 13.5 15.5 8.5 10.5 2 17" />
            <polyline points="16 7 22 7 22 13" />
          </svg>
          Equity Curve Overlay
        </div>
        <EquityCurveChart strategies={strategies} />
        <div className={s.chartLegend}>
          {strategies.map((strat, i) => (
            <div key={strat.key} className={s.legendItem}>
              <span className={s.legendDot} style={{ background: STRAT_COLORS[i] }} />
              {strat.label}
            </div>
          ))}
        </div>
      </GlassPanel>

      {/* ═══ 3. Drawdown Comparison ══════════════════════════════════════ */}
      <GlassPanel className={s.chartPanel}>
        <div className={s.sectionTitle}>
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke={T.red}
            strokeWidth="2" className={s.sectionIcon}>
            <polyline points="22 17 13.5 8.5 8.5 13.5 2 7" />
            <polyline points="16 17 22 17 22 11" />
          </svg>
          Drawdown Comparison
        </div>
        <DrawdownChart strategies={strategies} />
        <div className={s.chartLegend}>
          {strategies.map((strat, i) => (
            <div key={strat.key} className={s.legendItem}>
              <span className={s.legendDot} style={{ background: STRAT_COLORS[i] }} />
              {strat.label} ({strat.metrics?.max_drawdown
                ? `-${fmtPct(Math.abs(strat.metrics.max_drawdown) * 100)}`
                : '--'} max)
            </div>
          ))}
        </div>
      </GlassPanel>

      {/* ═══ 4. Region Performance ═══════════════════════════════════════ */}
      {allRegions.length > 0 && (
        <GlassPanel className={s.regionPanel}>
          <div className={s.sectionTitle}>
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke={T.purple}
              strokeWidth="2" className={s.sectionIcon}>
              <circle cx="12" cy="12" r="10" />
              <line x1="2" y1="12" x2="22" y2="12" />
              <path d="M12 2a15.3 15.3 0 014 10 15.3 15.3 0 01-4 10 15.3 15.3 0 01-4-10 15.3 15.3 0 014-10z" />
            </svg>
            Region Performance
          </div>
          <div className={s.regionGrid}>
            {allRegions.map(region => {
              return (
                <div key={region} className={s.regionCard}>
                  <div className={s.regionName}>
                    {strategies[0]?.region_performance?.[region]?.label || region}
                  </div>
                  <div className={s.regionMetrics}>
                    {strategies.map((strat, i) => {
                      const rp = strat.region_performance?.[region];
                      if (!rp) return (
                        <div key={strat.key} className={s.regionMetric}>
                          <span className={s.regionMetricLabel} style={{ color: STRAT_COLORS[i] }}>
                            {strat.label}
                          </span>
                          <span className={s.regionMetricValue} style={{ color: T.textSec }}>--</span>
                        </div>
                      );
                      return (
                        <div key={strat.key} className={s.regionMetric}>
                          <span className={s.regionMetricLabel} style={{ color: STRAT_COLORS[i] }}>
                            {strat.label}
                          </span>
                          <span className={s.regionMetricValue} style={{
                            color: (rp.profit_factor || 0) >= 2 ? T.green :
                              (rp.profit_factor || 0) >= 1.3 ? T.amber : T.red,
                          }}>
                            PF {fmtNum(rp.profit_factor)} | {fmtPct(rp.win_rate)}
                          </span>
                        </div>
                      );
                    })}
                  </div>
                </div>
              );
            })}
          </div>
        </GlassPanel>
      )}

      {/* ═══ 5. Signal Frequency ═════════════════════════════════════════ */}
      <GlassPanel className={s.freqPanel}>
        <div className={s.sectionTitle}>
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke={T.cyan}
            strokeWidth="2" className={s.sectionIcon}>
            <path d="M22 12h-4l-3 9L9 3l-3 9H2" />
          </svg>
          Signal Frequency
        </div>
        <div className={s.freqBars}>
          {strategies.map((strat, i) => {
            const freq = strat.metrics?.signal_frequency;
            const maxFreq = Math.max(...strategies.map(s => s.metrics?.signal_frequency || 0), 1);
            const barH = freq ? Math.max((freq / maxFreq) * 60, 4) : 4;
            return (
              <div key={strat.key} className={s.freqBarWrapper}>
                <span className={s.freqBarValue} style={{ color: STRAT_COLORS[i] }}>
                  {freq != null ? `${fmtNum(freq, 1)}/mo` : '--'}
                </span>
                <div className={s.freqBar}
                  style={{ height: `${barH}px`, background: STRAT_COLORS[i], opacity: 0.7 }} />
                <span className={s.freqBarLabel}>{strat.label}</span>
              </div>
            );
          })}
        </div>
      </GlassPanel>

      {/* ═══ 6. Risk-Adjusted Return Scatter ═════════════════════════════ */}
      <GlassPanel className={s.scatterPanel}>
        <div className={s.sectionTitle}>
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke={T.amber}
            strokeWidth="2" className={s.sectionIcon}>
            <circle cx="12" cy="12" r="3" />
            <circle cx="12" cy="12" r="8" strokeDasharray="2" />
          </svg>
          Risk vs Return
        </div>
        <RiskScatterPlot strategies={strategies} />
        <div className={s.chartLegend}>
          {strategies.map((strat, i) => (
            <div key={strat.key} className={s.legendItem}>
              <span className={s.legendDot} style={{ background: STRAT_COLORS[i] }} />
              {strat.label}
            </div>
          ))}
        </div>
      </GlassPanel>

      {/* ═══ 7. Verdict ═════════════════════════════════════════════════ */}
      {verdict.recommendation && (
        <GlassPanel className={s.verdictPanel}>
          <div className={s.sectionTitle}>
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke={T.green}
              strokeWidth="2" className={s.sectionIcon}>
              <path d="M22 11.08V12a10 10 0 11-5.93-9.14" />
              <polyline points="22 4 12 14.01 9 11.01" />
            </svg>
            Verdict
          </div>
          <div className={s.verdictHeader}>
            <span style={{ color: T.textSec, fontFamily: T.sans, fontSize: 13 }}>
              Recommended:
            </span>
            <span className={s.verdictBadge}>
              {verdict.recommendation_label || verdict.recommendation}
            </span>
          </div>
          <div className={s.verdictReasons}>
            {(verdict.reasoning || []).map((reason, i) => (
              <div key={i} className={s.verdictReason}>{reason}</div>
            ))}
          </div>
          {verdict.scores && (
            <div className={s.verdictScoreBar}>
              {verdict.scores.map((sc, i) => (
                <div key={sc.key} className={s.scoreCard}
                  style={{
                    borderColor: sc.key === verdict.recommendation
                      ? `${T.green}44` : undefined,
                  }}>
                  <div className={s.scoreCardLabel}>{sc.label}</div>
                  <div className={s.scoreCardValue} style={{
                    color: sc.key === verdict.recommendation ? T.green : STRAT_COLORS[i],
                  }}>
                    {((sc.composite || 0) * 100).toFixed(1)}
                  </div>
                </div>
              ))}
            </div>
          )}
        </GlassPanel>
      )}
    </div>
  );
}
